   363→## src/hooks/useDashboardData.ts
   364→```
   365→import { useState, useEffect, useMemo, useCallback } from 'react';
   366→import type { Verkaeufer, Artikel, Kaeufer, Verkaeufe } from '@/types/app';
   367→import { LivingAppsService } from '@/services/livingAppsService';
   368→
   369→export function useDashboardData() {
   370→  const [verkaeufer, setVerkaeufer] = useState<Verkaeufer[]>([]);
   371→  const [artikel, setArtikel] = useState<Artikel[]>([]);
   372→  const [kaeufer, setKaeufer] = useState<Kaeufer[]>([]);
   373→  const [verkaeufe, setVerkaeufe] = useState<Verkaeufe[]>([]);
   374→  const [loading, setLoading] = useState(true);
   375→  const [error, setError] = useState<Error | null>(null);
   376→
   377→  const fetchAll = useCallback(async () => {
   378→    setError(null);
   379→    try {
   380→      const [verkaeuferData, artikelData, kaeuferData, verkaeufeData] = await Promise.all([
   381→        LivingAppsService.getVerkaeufer(),
   382→        LivingAppsService.getArtikel(),
   383→        LivingAppsService.getKaeufer(),
   384→        LivingAppsService.getVerkaeufe(),
   385→      ]);
   386→      setVerkaeufer(verkaeuferData);
   387→      setArtikel(artikelData);
   388→      setKaeufer(kaeuferData);
   389→      setVerkaeufe(verkaeufeData);
   390→    } catch (err) {
   391→      setError(err instanceof Error ? err : new Error('Fehler beim Laden der Daten'));
   392→    } finally {
   393→      setLoading(false);
   394→    }
   395→  }, []);
   396→
   397→  useEffect(() => { fetchAll(); }, [fetchAll]);
   398→
   399→  const verkaeuferMap = useMemo(() => {
   400→    const m = new Map<string, Verkaeufer>();
   401→    verkaeufer.forEach(r => m.set(r.record_id, r));
   402→    return m;
   403→  }, [verkaeufer]);
   404→
   405→  const artikelMap = useMemo(() => {
   406→    const m = new Map<string, Artikel>();
   407→    artikel.forEach(r => m.set(r.record_id, r));
   408→    return m;
   409→  }, [artikel]);
   410→
   411→  const kaeuferMap = useMemo(() => {
   412→    const m = new Map<string, Kaeufer>();
   413→    kaeufer.forEach(r => m.set(r.record_id, r));
   414→    return m;
   415→  }, [kaeufer]);
   416→
   417→  return { verkaeufer, setVerkaeufer, artikel, setArtikel, kaeufer, setKaeufer, verkaeufe, setVerkaeufe, loading, error, fetchAll, verkaeuferMap, artikelMap, kaeuferMap };
   418→}
   419→```
