   438→import type { EnrichedArtikel, EnrichedVerkaeufe } from '@/types/enriched';
   439→import type { Artikel, Kaeufer, Verkaeufe, Verkaeufer } from '@/types/app';
   440→import { extractRecordId } from '@/services/livingAppsService';
   441→
   442→// eslint-disable-next-line @typescript-eslint/no-explicit-any
   443→function resolveDisplay(url: string | undefined, map: Map<string, any>, ...fields: string[]): string {
   444→  if (!url) return '';
   445→  const id = extractRecordId(url);
   446→  if (!id) return '';
   447→  const r = map.get(id);
   448→  if (!r) return '';
   449→  return fields.map(f => String(r.fields[f] ?? '')).join(' ').trim();
   450→}
   451→
   452→interface ArtikelMaps {
   453→  verkaeuferMap: Map<string, Verkaeufer>;
   454→}
   455→
   456→export function enrichArtikel(
   457→  artikel: Artikel[],
   458→  maps: ArtikelMaps
   459→): EnrichedArtikel[] {
   460→  return artikel.map(r => ({
   461→    ...r,
   462→    verkaeuferName: resolveDisplay(r.fields.verkaeufer, maps.verkaeuferMap, 'vorname', 'nachname'),
   463→  }));
   464→}
   465→
   466→interface VerkaeufeMaps {
   467→  artikelMap: Map<string, Artikel>;
   468→  kaeuferMap: Map<string, Kaeufer>;
   469→}
   470→
   471→export function enrichVerkaeufe(
   472→  verkaeufe: Verkaeufe[],
   473→  maps: VerkaeufeMaps
   474→): EnrichedVerkaeufe[] {
   475→  return verkaeufe.map(r => ({
   476→    ...r,
   477→    artikelName: resolveDisplay(r.fields.artikel, maps.artikelMap, 'artikelnummer'),
   478→    kaeuferName: resolveDisplay(r.fields.kaeufer, maps.kaeuferMap, 'vorname', 'nachname'),
   479→  }));
   480→}
