   510→type CompletionOptions = {
   511→  temperature?: number;
   512→  max_tokens?: number;
   513→  top_p?: number;
   514→  stop?: string[];
   515→  response_format?: { type: string };
   516→};
   517→
   518→export async function chatCompletion(
   519→  messages: ChatMessage[],
   520→  options: CompletionOptions = {}
   521→): Promise<string> {
   522→  const res = await fetch(AI_ENDPOINT, {
   523→    method: "POST",
   524→    headers: { "Content-Type": "application/json", Accept: "application/json" },
   525→    body: JSON.stringify({ model: AI_MODEL, messages, ...options }),
   526→  });
   527→  if (!res.ok) {
   528→    const body = await res.text();
   529→    throw new Error(`AI API ${res.status}: ${body}`);
   530→  }
   531→  const data = await res.json();
   532→  return data.choices[0].message.content;
   533→}
   534→
   535→export async function safeJsonCompletion<T = unknown>(
   536→  messages: ChatMessage[],
   537→  options: CompletionOptions = {}
   538→): Promise<T> {
   539→  const raw = await chatCompletion(messages, options);
   540→  const match = raw.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
   541→  if (!match) throw new Error(`Expected JSON but got: ${raw.slice(0, 200)}`);
   542→  return JSON.parse(match[0]);
   543→}
   544→
   545→export async function withRetry<T>(fn: () => Promise<T>, maxAttempts = 3): Promise<T> {
   546→  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
   547→    try {
   548→      return await fn();
   549→    } catch (err) {
   550→      if (attempt === maxAttempts) throw err;
   551→      await new Promise((r) => setTimeout(r, 1000 * attempt));
   552→    }
   553→  }
   554→  throw new Error("unreachable");
   555→}
   556→
   557→// --- File encoding helpers ---
   558→
   559→export function fileToDataUri(file: File): Promise<string> {
   560→  return new Promise((resolve, reject) => {
   561→    const reader = new FileReader();
   562→    reader.onload = () => resolve(reader.result as string);
   563→    reader.onerror = () => reject(new Error("Failed to read file"));
   564→    reader.readAsDataURL(file);
   565→  });
   566→}
   567→
   568→export async function urlToDataUri(url: string): Promise<string> {
   569→  const res = await fetch(url);
   570→  const blob = await res.blob();
   571→  return new Promise((resolve, reject) => {
   572→    const reader = new FileReader();
   573→    reader.onload = () => resolve(reader.result as string);
   574→    reader.onerror = () => reject(new Error("Failed to encode file"));
   575→    reader.readAsDataURL(blob);
   576→  });
   577→}
