   579→// --- High-level AI features ---
   580→
   581→export async function classify(
   582→  text: string,
   583→  categories: string[]
   584→): Promise<{ category: string; confidence: number }> {
   585→  return safeJsonCompletion([
   586→    {
   587→      role: "system",
   588→      content: [
   589→        "You are a classifier. Respond ONLY with valid JSON, nothing else.",
   590→        'Output format: {"category": "<one of the allowed categories>", "confidence": <0-1>}',
   591→        `Allowed categories: ${JSON.stringify(categories)}`,
   592→      ].join("\n"),
   593→    },
   594→    { role: "user", content: text },
   595→  ], { temperature: 0 });
   596→}
   597→
   598→export async function extract<T = Record<string, unknown>>(
   599→  text: string,
   600→  schemaDescription: string
   601→): Promise<T> {
   602→  return safeJsonCompletion([
   603→    {
   604→      role: "system",
