   606→        "You are a data extraction engine. Respond ONLY with valid JSON matching the requested schema.",
   607→        "If a field cannot be determined from the input, use null.",
   608→        `Schema:\n${schemaDescription}`,
   609→      ].join("\n"),
   610→    },
   611→    { role: "user", content: text },
   612→  ], { temperature: 0 });
   613→}
   614→
   615→export async function summarize(
   616→  text: string,
   617→  options: { maxSentences?: number; language?: string } = {}
   618→): Promise<string> {
   619→  const { maxSentences = 3, language } = options;
   620→  const instructions = [
   621→    `Summarize the following text in at most ${maxSentences} sentences.`,
   622→    "Be concise and preserve key facts.",
   623→  ];
   624→  if (language) instructions.push(`Write the summary in ${language}.`);
   625→  return chatCompletion([
   626→    { role: "system", content: instructions.join(" ") },
   627→    { role: "user", content: text },
   628→  ]);
   629→}
   630→
   631→export async function translate(
