   101→      return true;
   102→    });
   103→  }, [enrichedArtikel, filterKategorie, filterVerfuegbar, soldArtikelIds]);
   104→
   105→  const totalUmsatz = verkaeufe.reduce((s, v) => s + (v.fields.verkaufspreis ?? 0), 0);
