   171→          icon={<Users size={18} className="text-muted-foreground" />}
   172→        />
   173→      </div>
   174→
   175→      {/* Main Content: Artikel Board + Sidebar */}
   176→      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
   177→        {/* Artikel Board (2/3 width) */}
   178→        <div className="lg:col-span-2 space-y-4">
   179→          {/* Filters */}
   180→          <div className="flex flex-wrap gap-2 items-center">
   181→            <Filter size={14} className="text-muted-foreground shrink-0" />
   182→            <div className="flex flex-wrap gap-1.5">
   183→              {['alle', 'verfuegbar', 'verkauft'].map(f => (
   184→                <button
