   191→                  }`}
   192→                >
   193→                  {f === 'alle' ? 'Alle' : f === 'verfuegbar' ? 'Verfügbar' : 'Verkauft'}
   194→                </button>
   195→              ))}
   196→            </div>
   197→            <div className="flex flex-wrap gap-1.5 ml-2">
   198→              <button
   199→                onClick={() => setFilterKategorie('alle')}
   200→                className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
   201→                  filterKategorie === 'alle'
   202→                    ? 'bg-primary text-primary-foreground'
   203→                    : 'bg-muted text-muted-foreground hover:bg-accent hover:text-accent-foreground'
   204→                }`}
   205→              >
   206→                Alle Kategorien
   207→              </button>
   208→              {kategorienData.map(k => (
   209→                <button
   210→                  key={k.key}
   211→                  onClick={() => setFilterKategorie(k.key)}
   212→                  className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
   213→                    filterKategorie === k.key
   214→                      ? 'bg-primary text-primary-foreground'
