   476→        onConfirm={async () => {
   477→          if (deleteVerkaufTarget) {
   478→            await LivingAppsService.deleteVerkaeufeEntry(deleteVerkaufTarget.record_id);
   479→            fetchAll();
   480→          }
   481→          setDeleteVerkaufTarget(null);
   482→        }}
   483→        onClose={() => setDeleteVerkaufTarget(null)}
   484→      />
   485→    </div>
   486→  );
   487→}
   488→
   489→function DashboardSkeleton() {
   490→  return (
   491→    <div className="space-y-6">
   492→      <div className="flex items-center justify-between">
   493→        <Skeleton className="h-8 w-48" />
   494→        <Skeleton className="h-9 w-36" />
   495→      </div>
   496→      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
   497→        {[...Array(4)].map((_, i) => <Skeleton key={i} className="h-24 rounded-2xl" />)}
   498→      </div>
   499→      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
   500→        <div className="lg:col-span-2 grid grid-cols-2 gap-3">
   501→          {[...Array(6)].map((_, i) => <Skeleton key={i} className="h-40 rounded-2xl" />)}
   502→        </div>
   503→        <div className="space-y-4">
   504→          <Skeleton className="h-56 rounded-2xl" />
   505→          <Skeleton className="h-64 rounded-2xl" />
   506→        </div>
   507→      </div>
   508→    </div>
